// NL-DPE Attention Head Top — Q/K/V projections + buffers + DIMM
// AUTO-GENERATED by nl_dpe/gen_nldpe_attn_head_top.py — DO NOT EDIT BY HAND
//
// Composition (matches IMC sim's attention_model — no output projection):
//
//   [valid_x, data_in_x] ──► fc_top_qkv ×3 (Q/K/V projections)
//                                │     │     │
//                                ▼     ▼     ▼
//                             q_buf k_buf v_buf  (sram)
//                                │     │     │
//                                └─────┴─────┘
//                                      ▼
//                             nldpe_dimm_top (W=16 lanes, 1 fire)
//                                      ▼
//                                [data_out, valid_n]
//
// Locked parameters (see gen_nldpe_attn_head_top.py for derivation):
//   d_model=128, d_head=64, N_SEQ=128, C=128, W=16
//   PACKED_KQ=26 (input words/inference)
//   PACKED_NQ=13 (output words/inference)
//
// Resource expectation:
//   - 3 × fc_top_qkv         (instances: fc_q_inst, fc_k_inst, fc_v_inst)
//   - 3 × sram               (instances: q_buffer, k_buffer, v_buffer)
//   - 1 × nldpe_dimm_top     (instance:  dimm_inst)
//   - 0 × fc_top_o           (NO output projection)
//
// Module dependencies (compile together with this file):
//   - fc_verification/rtl/nldpe_dimm_top_d64_c128.v
//   - fc_verification/rtl/nldpe/fc_top_qkv.v
//   - fc_verification/dpe_stub.v

`timescale 1ns / 1ps

module nldpe_attn_head_d64_c128 #(
    parameter DATA_WIDTH = 40,
    parameter D_MODEL    = 128,
    parameter D_HEAD     = 64,
    parameter N_SEQ      = 128,
    parameter C          = 128,
    parameter W          = 16
)(
    input  wire                    clk,
    input  wire                    rst,
    input  wire                    valid_x,
    input  wire [DATA_WIDTH-1:0]   data_in_x,
    input  wire                    ready_n,
    output wire [DATA_WIDTH-1:0]   data_out,
    output wire                    ready_x,
    output wire                    valid_n
);

    // ─── Local constants (must match generator) ────────────────────
    localparam PACKED_KQ        = 26; // ceil(d_model/EPW), in words
    localparam PACKED_NQ        = 13; // ceil(d_head/EPW),  in words
    localparam N_X_INPUT_WORDS  = 3328;   // N × PACKED_KQ
    localparam N_FC_OUT_WORDS   = 1664; // N × PACKED_NQ
    localparam BUFFER_DEPTH     = 1665;      // N × PACKED_NQ + 1
    localparam DIMM_Q_WORDS     = 14;
    localparam DIMM_K_WORDS     = 1664;
    localparam DIMM_V_WORDS     = 1664;

    // ─── FSM ───────────────────────────────────────────────────────
    localparam S_IDLE      = 3'd0;
    localparam S_FEED_X    = 3'd1;
    localparam S_DRAIN_FC  = 3'd2;
    localparam S_FIRE_DIMM = 3'd3;
    localparam S_OUTPUT    = 3'd4;
    reg [2:0] state;

    reg [11:0] in_count;       // X words consumed (0..N_X_INPUT_WORDS)
    reg [10:0] write_addr;    // q/k/v_buffer write address
    reg [10:0] read_addr;     // q/k/v_buffer read address
    reg [10:0] dimm_q_count; // valid_q pulses already issued
    reg [10:0] dimm_k_count; // valid_k pulses already issued
    reg [10:0] dimm_v_count; // valid_v pulses already issued
    reg drive_valid_q, drive_valid_k, drive_valid_v;

    // ─── Q/K/V projection arms ─────────────────────────────────────
    wire [DATA_WIDTH-1:0] q_fc_out, k_fc_out, v_fc_out;
    wire q_fc_valid_n, k_fc_valid_n, v_fc_valid_n;
    wire q_fc_ready,   k_fc_ready,   v_fc_ready;

    wire feed_x_now = (state == S_FEED_X) && valid_x;

    fc_top_qkv #(.DATA_WIDTH(DATA_WIDTH)) fc_q_inst (
        .clk(clk), .rst(rst),
        .valid(feed_x_now), .ready_n(1'b0),
        .data_in(data_in_x),
        .data_out(q_fc_out),
        .ready(q_fc_ready), .valid_n(q_fc_valid_n)
    );
    fc_top_qkv #(.DATA_WIDTH(DATA_WIDTH)) fc_k_inst (
        .clk(clk), .rst(rst),
        .valid(feed_x_now), .ready_n(1'b0),
        .data_in(data_in_x),
        .data_out(k_fc_out),
        .ready(k_fc_ready), .valid_n(k_fc_valid_n)
    );
    fc_top_qkv #(.DATA_WIDTH(DATA_WIDTH)) fc_v_inst (
        .clk(clk), .rst(rst),
        .valid(feed_x_now), .ready_n(1'b0),
        .data_in(data_in_x),
        .data_out(v_fc_out),
        .ready(v_fc_ready), .valid_n(v_fc_valid_n)
    );

    // ─── Q/K/V buffers (sram, depth = N × PACKED_NQ + 1) ────────────
    // write_addr increments on each FC valid_n; read_addr increments
    // when DIMM is driven from the corresponding buffer.
    wire [DATA_WIDTH-1:0] q_buf_out, k_buf_out, v_buf_out;

    sram #(.N_CHANNELS(1), .DATA_WIDTH(DATA_WIDTH), .DEPTH(BUFFER_DEPTH))
    q_buffer (
        .clk(clk), .rst(rst),
        .w_en(q_fc_valid_n),
        .r_addr(read_addr),
        .w_addr(write_addr),
        .sram_data_in(q_fc_out),
        .sram_data_out(q_buf_out)
    );
    sram #(.N_CHANNELS(1), .DATA_WIDTH(DATA_WIDTH), .DEPTH(BUFFER_DEPTH))
    k_buffer (
        .clk(clk), .rst(rst),
        .w_en(k_fc_valid_n),
        .r_addr(read_addr),
        .w_addr(write_addr),
        .sram_data_in(k_fc_out),
        .sram_data_out(k_buf_out)
    );
    sram #(.N_CHANNELS(1), .DATA_WIDTH(DATA_WIDTH), .DEPTH(BUFFER_DEPTH))
    v_buffer (
        .clk(clk), .rst(rst),
        .w_en(v_fc_valid_n),
        .r_addr(read_addr),
        .w_addr(write_addr),
        .sram_data_in(v_fc_out),
        .sram_data_out(v_buf_out)
    );

    // Track the number of FC valid_n pulses observed (Q is canonical;
    // K/V fire in lockstep because all 3 FCs share the same `valid`).
    reg [10:0] fc_out_count;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            write_addr   <= 0;
            fc_out_count <= 0;
        end else if (q_fc_valid_n) begin
            write_addr   <= write_addr   + 1;
            fc_out_count <= fc_out_count + 1;
        end
    end

    // ─── DIMM instance (single fire over buffered Q/K/V) ────────────
    wire [DATA_WIDTH-1:0] dimm_data_out;
    wire dimm_valid_n;
    wire dimm_ready_q, dimm_ready_k, dimm_ready_v;

    nldpe_dimm_top #(
        .N(N_SEQ), .D(D_HEAD), .W(W), .DATA_WIDTH(DATA_WIDTH)
    ) dimm_inst (
        .clk(clk), .rst(rst),
        .valid_q(drive_valid_q), .valid_k(drive_valid_k), .valid_v(drive_valid_v),
        .ready_n(ready_n),
        .data_in_q(q_buf_out), .data_in_k(k_buf_out), .data_in_v(v_buf_out),
        .data_out(dimm_data_out),
        .ready_q(dimm_ready_q), .ready_k(dimm_ready_k), .ready_v(dimm_ready_v),
        .valid_n(dimm_valid_n)
    );

    // ─── Top-level FSM ─────────────────────────────────────────────
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state          <= S_IDLE;
            in_count       <= 0;
            read_addr      <= 0;
            dimm_q_count   <= 0;
            dimm_k_count   <= 0;
            dimm_v_count   <= 0;
            drive_valid_q  <= 1'b0;
            drive_valid_k  <= 1'b0;
            drive_valid_v  <= 1'b0;
        end else begin
            case (state)
                S_IDLE: begin
                    if (valid_x) state <= S_FEED_X;
                end
                S_FEED_X: begin
                    if (valid_x) in_count <= in_count + 1;
                    if (in_count + 1 == N_X_INPUT_WORDS) begin
                        state <= S_DRAIN_FC;
                    end
                end
                S_DRAIN_FC: begin
                    // Wait until all PACKED_NQ × N FC outputs are buffered.
                    if (fc_out_count >= N_FC_OUT_WORDS) begin
                        state         <= S_FIRE_DIMM;
                        read_addr     <= 0;
                        drive_valid_q <= 1'b1;
                    end
                end
                S_FIRE_DIMM: begin
                    // Phase A: drive valid_q for DIMM_Q_WORDS cycles.
                    // Phase B: drive valid_k for DIMM_K_WORDS cycles.
                    // Phase C: drive valid_v for DIMM_V_WORDS cycles.
                    // read_addr advances in lockstep with the active phase.
                    if (drive_valid_q) begin
                        dimm_q_count <= dimm_q_count + 1;
                        read_addr    <= read_addr + 1;
                        if (dimm_q_count + 1 == DIMM_Q_WORDS) begin
                            drive_valid_q <= 1'b0;
                            drive_valid_k <= 1'b1;
                            read_addr     <= 0;
                        end
                    end else if (drive_valid_k) begin
                        dimm_k_count <= dimm_k_count + 1;
                        read_addr    <= read_addr + 1;
                        if (dimm_k_count + 1 == DIMM_K_WORDS) begin
                            drive_valid_k <= 1'b0;
                            drive_valid_v <= 1'b1;
                            read_addr     <= 0;
                        end
                    end else if (drive_valid_v) begin
                        dimm_v_count <= dimm_v_count + 1;
                        read_addr    <= read_addr + 1;
                        if (dimm_v_count + 1 == DIMM_V_WORDS) begin
                            drive_valid_v <= 1'b0;
                            state         <= S_OUTPUT;
                        end
                    end
                end
                S_OUTPUT: begin
                    // Pass-through: DIMM internally proceeds through
                    // mac_qk → softmax → mac_sv and emits valid_n; the
                    // top-level outputs are wired directly below.
                end
                default: state <= S_IDLE;
            endcase
        end
    end

    // ─── Top-level handshake / outputs ─────────────────────────────
    // Accept new X words only while feeding the FCs.
    assign ready_x  = (state == S_FEED_X) && q_fc_ready && k_fc_ready && v_fc_ready;
    assign data_out = dimm_data_out;
    assign valid_n  = (state == S_OUTPUT) && dimm_valid_n;

endmodule
